/**
 * Student Class Finder Page
 * Shows all enrolled courses with room, building, time, days
 * Data: GET /student/timetable (uses same endpoint, shows all sessions)
 */

import React, { useState, useEffect } from 'react';
import { getMyTimetable, findMyCurrentClass } from '../../services/student_service';

const StudentClassFinder = () => {
    const [courses, setCourses] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [search, setSearch] = useState('');
    const [currentClass, setCurrentClass] = useState(null);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);

        // Fetch all timetable entries
        const timetableResult = await getMyTimetable();

        // Fetch current class
        const currentResult = await findMyCurrentClass();
        if (currentResult.success && currentResult.hasClass) {
            setCurrentClass(currentResult.data);
        }

        if (timetableResult.success) {
            // Group by course_code + section to show unique courses
            const data = timetableResult.data || [];
            const courseMap = {};
            data.forEach(item => {
                const key = `${item.course_code}-${item.section}`;
                if (!courseMap[key]) {
                    courseMap[key] = {
                        course_code: item.course_code,
                        course_name: item.course_name,
                        section: item.section,
                        room_number: item.room_number,
                        building: item.building || 'Campus',
                        instructor: item.teacher_name || item.instructor || 'TBD',
                        days: [],
                        start_time: item.start_time,
                        end_time: item.end_time,
                    };
                }
                if (item.day && !courseMap[key].days.includes(item.day)) {
                    courseMap[key].days.push(item.day);
                }
            });
            setCourses(Object.values(courseMap));
        } else {
            setError(timetableResult.message);
        }

        setLoading(false);
    };

    const formatDays = (days) => {
        const dayMap = { Monday: 'Mon', Tuesday: 'Tue', Wednesday: 'Wed', Thursday: 'Thu', Friday: 'Fri' };
        return days.map(d => dayMap[d] || d).join(', ');
    };

    const formatTime = (start, end) => {
        if (!start || !end) return 'TBD';
        const fmt = t => {
            const [h, m] = t.split(':');
            const hr = parseInt(h);
            const suffix = hr >= 12 ? 'PM' : 'AM';
            return `${hr > 12 ? hr - 12 : hr || 12}:${m} ${suffix}`;
        };
        return `${fmt(start)} – ${fmt(end)}`;
    };

    const filtered = courses.filter(c =>
        c.course_code?.toLowerCase().includes(search.toLowerCase()) ||
        c.course_name?.toLowerCase().includes(search.toLowerCase()) ||
        c.instructor?.toLowerCase().includes(search.toLowerCase())
    );

    const sectionColors = ['#3b82f6', '#8b5cf6', '#10b981', '#f59e0b', '#ef4444', '#06b6d4'];

    if (loading) {
        return (
            <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '60vh', flexDirection: 'column', gap: '16px' }}>
                <div style={{ width: '40px', height: '40px', border: '3px solid #e5e7eb', borderTopColor: '#7c3aed', borderRadius: '50%', animation: 'spin 0.8s linear infinite' }}></div>
                <span style={{ color: '#64748b', fontSize: '14px' }}>Loading your classes...</span>
            </div>
        );
    }

    return (
        <div style={{ padding: '0' }}>
            {/* Header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '28px' }}>
                <div>
                    <h1 style={{ fontSize: '26px', fontWeight: '800', color: '#1e293b', marginBottom: '4px' }}>Class Locator</h1>
                    <p style={{ color: '#64748b', fontSize: '14px' }}>Find your classes and their locations</p>
                </div>
                {currentClass && (
                    <div style={{
                        display: 'flex', alignItems: 'center', gap: '10px',
                        background: '#f0fdf4', border: '1px solid #bbf7d0',
                        padding: '10px 16px', borderRadius: '10px'
                    }}>
                        <span style={{ width: '8px', height: '8px', background: '#22c55e', borderRadius: '50%', display: 'inline-block', animation: 'pulse 2s infinite' }}></span>
                        <div>
                            <div style={{ fontSize: '10px', fontWeight: '700', color: '#166534', letterSpacing: '0.05em' }}>NOW IN CLASS</div>
                            <div style={{ fontSize: '13px', fontWeight: '700', color: '#15803d' }}>{currentClass.course_code} · {currentClass.room_number}</div>
                        </div>
                    </div>
                )}
            </div>

            {/* Search */}
            <div style={{ position: 'relative', marginBottom: '28px' }}>
                <svg style={{ position: 'absolute', left: '16px', top: '50%', transform: 'translateY(-50%)', color: '#94a3b8' }} width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/>
                </svg>
                <input
                    type="text"
                    value={search}
                    onChange={e => setSearch(e.target.value)}
                    placeholder="Search by course code, name, or instructor..."
                    style={{
                        width: '100%', padding: '13px 16px 13px 46px',
                        border: '1px solid #e5e7eb', borderRadius: '12px',
                        fontSize: '14px', background: 'white',
                        boxShadow: '0 1px 3px rgba(0,0,0,0.06)',
                        outline: 'none', boxSizing: 'border-box'
                    }}
                />
            </div>

            {error && (
                <div style={{ background: '#fef2f2', border: '1px solid #fecaca', color: '#b91c1c', padding: '14px 18px', borderRadius: '10px', marginBottom: '20px', fontSize: '14px' }}>
                    {error}
                </div>
            )}

            {/* Course Cards */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {filtered.length === 0 ? (
                    <div style={{ textAlign: 'center', padding: '60px', color: '#94a3b8', background: 'white', borderRadius: '16px', border: '1px solid #e5e7eb' }}>
                        {search ? 'No courses match your search.' : 'No enrolled courses found. Make sure your backend is running.'}
                    </div>
                ) : (
                    filtered.map((course, idx) => {
                        const color = sectionColors[idx % sectionColors.length];
                        const isCurrent = currentClass?.course_code === course.course_code;
                        return (
                            <div key={`${course.course_code}-${idx}`} style={{
                                background: 'white',
                                borderRadius: '16px',
                                border: `1px solid ${isCurrent ? '#bbf7d0' : '#e5e7eb'}`,
                                overflow: 'hidden',
                                boxShadow: isCurrent ? '0 0 0 2px #22c55e' : '0 1px 4px rgba(0,0,0,0.05)'
                            }}>
                                {/* Course header */}
                                <div style={{ padding: '18px 20px 12px', borderBottom: `1px solid #f1f5f9`, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                        <span style={{ fontSize: '15px', fontWeight: '800', color: color }}>{course.course_code}</span>
                                        <span style={{ fontSize: '11px', fontWeight: '700', color: color, background: `${color}15`, padding: '2px 8px', borderRadius: '6px' }}>
                                            Section {course.section}
                                        </span>
                                        <span style={{ fontSize: '14px', fontWeight: '600', color: '#1e293b' }}>{course.course_name}</span>
                                    </div>
                                    <span style={{
                                        fontSize: '11px', fontWeight: '700',
                                        background: isCurrent ? '#dcfce7' : '#f0fdf4',
                                        color: isCurrent ? '#166534' : '#15803d',
                                        padding: '4px 10px', borderRadius: '20px',
                                        border: `1px solid ${isCurrent ? '#bbf7d0' : '#d1fae5'}`
                                    }}>
                                        {isCurrent ? '● Live Now' : '✓ Enrolled'}
                                    </span>
                                </div>

                                {/* Course details grid */}
                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr 1fr', gap: '0' }}>
                                    {[
                                        { label: 'ROOM', value: course.room_number || 'N/A', icon: '🚪' },
                                        { label: 'BUILDING', value: course.building || 'Campus', icon: '🏛️' },
                                        { label: 'TIME', value: formatTime(course.start_time, course.end_time), icon: '⏰' },
                                        { label: 'DAYS', value: course.days.length > 0 ? formatDays(course.days) : 'TBD', icon: '📅' },
                                    ].map((detail, di) => (
                                        <div key={di} style={{
                                            padding: '14px 20px',
                                            borderRight: di < 3 ? '1px solid #f1f5f9' : 'none',
                                            background: '#fafafa'
                                        }}>
                                            <div style={{ fontSize: '10px', fontWeight: '700', color: '#94a3b8', letterSpacing: '0.06em', marginBottom: '6px' }}>{detail.label}</div>
                                            <div style={{ fontSize: '13px', fontWeight: '600', color: '#374151' }}>{detail.value}</div>
                                        </div>
                                    ))}
                                </div>

                                {/* Instructor */}
                                <div style={{ padding: '12px 20px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                    <div style={{
                                        width: '26px', height: '26px', borderRadius: '50%',
                                        background: `${color}20`, color: color,
                                        display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '12px'
                                    }}>
                                        <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/>
                                        </svg>
                                    </div>
                                    <span style={{ fontSize: '13px', color: '#475569', fontWeight: '500' }}>{course.instructor}</span>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>

            <style>{`
                @keyframes spin { to { transform: rotate(360deg); } }
                @keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.4; } }
            `}</style>
        </div>
    );
};

export default StudentClassFinder;
